external_knowledge:
High risk level: total_anomaly_count > 0 and percent_energy_to_battery_max > 50; 
Medium risk level: total_anomaly_count > 0 and percent_energy_to_battery_max <= 50; 
Low risk level: total_anomaly_count = 0.

sql:
SELECT total_energy_consumed
FROM device_stats
WHERE device_id = 0;

SELECT session_id, max_energy_consumption
FROM energy_stats
WHERE max_energy_consumption = (SELECT MAX(max_energy_consumption) FROM energy_stats);

SELECT avg_left_energy, avg_right_energy
FROM energy_stats
WHERE session_id = 1;

SELECT session_id, AVG(avg_left_energy) AS avg_left_energy, AVG(avg_right_energy) AS avg_right_energy
FROM energy_stats
GROUP BY session_id;

SELECT AVG(total_energy_consumed) AS avg_total_energy
FROM device_stats
WHERE last_updated = '2023-06-30 12:00:00';

SELECT device_id, SUM(total_energy_consumed) as total_energy
FROM device_stats
GROUP BY device_id;
